  "Jump straight into creation with templates tailored for common workflows.": { en: "Jump straight into creation with templates tailored for common workflows.", ar: "ابدأ الإنشاء فورًا بقوالب مصممة للمهام الشائعة.", "ar-eg": "ابدأ على طول بقوالب معمولة للمهام المتكررة." },
  "Keep characters, styles, and layouts aligned across every project.": { en: "Keep characters, styles, and layouts aligned across every project.", ar: "حافظ على تناسق الشخصيات والأساليب والتخطيطات في كل مشروع.", "ar-eg": "خلّي الشخصيات والستايلات والتخطيطات ثابتة في كل مشروع." },
  "Build on a strong foundation and refine until it feels right.": { en: "Build on a strong foundation and refine until it feels right.", ar: "ابدأ من أساس قوي وحسّن النتيجة حتى تصل لما تريد.", "ar-eg": "ابدأ من أساس قوي وظبط لحد ما النتيجة تبقى مظبوطة." },
  "Skip the trial and error. Blueprints are pre-designed templates that give you a structured starting point, saving time and ensuring your outputs stay consistent, polished, and on-brand.": { en: "Skip the trial and error. Blueprints are pre-designed templates that give you a structured starting point, saving time and ensuring your outputs stay consistent, polished, and on-brand.", ar: "تجاوز التجربة العشوائية. القوالب تمنحك بداية منظمة وتوفر الوقت وتحافظ على اتساق وجودة النتائج.", "ar-eg": "سيب التجربة العشوائية. القوالب بتديك بداية منظمة، بتوفر وقت، وبتخلي النتائج ثابتة وشيك." },
  "Generate with Blueprints": { en: "Generate with Blueprints", ar: "ولّد باستخدام القوالب", "ar-eg": "ولّد بالقوالب" },

