  "Disclaimer of Warranties": { en: "Disclaimer of Warranties", ar: "إخلاء المسؤولية من الضمانات", "ar-eg": "إخلاء مسؤولية الضمانات", es: "Renuncia de garantías", fr: "Exclusion de garanties", de: "Gewährleistungsausschluss", pt: "Isenção de garantias", it: "Esclusione di garanzia", tr: "Garanti Reddi", ru: "Отказ от гарантий", zh: "免责声明", ja: "保証の免責", ko: "보증의 면제", hi: "वारंटी का अस्वीकरण", id: "Penafian Jaminan", nl: "Uitsluiting van garantie", sv: "Ansvarsfriskrivning för garantier", cs: "Vyloučení záruk", ro: "Exonerarea de garanții", el: "Αποποίηση Εγγυήσεων", uk: "Відмова від гарантій", he: "התנערות מאחריות לחיוביות", fa: "سلب مسئولیت ضمانت‌ها", vi: "Tuyên bố miễn trừ bảo hành", th: "ข้อสงวนสิทธิ์การรับประกัน", pl: "Wyłączenie rękojmi" },
  "AI Disclaimer": { en: "AI Disclaimer", ar: "إخلاء مسؤولية الذكاء الاصطناعي", "ar-eg": "إخلاء مسؤولية الذكاء الاصطناعي", es: "Aviso legal de IA", fr: "Avertissement IA", de: "KI-Haftungsausschluss", pt: "Aviso de IA", it: "Disclaimer IA", tr: "Yapay Zeka Sorumluluk Reddi", ru: "Дисклеймер ИИ", zh: "AI 免责声明", ja: "AIに関する免責点", ko: "AI 면책 조항", hi: "AI अस्वीकरण", id: "Penafian AI", nl: "AI-disclaimer", sv: "AI-friskrivning", cs: "Prohlášení k AI", ro: "Declinarea responsabilității AI", el: "Αποποίηση ευθυνών AI", uk: "Відмова від відповідальності за ШІ", he: "הצהרת AI", fa: "سلب مسئولیت هوش مصنوعی", vi: "Tuyên bố miễn trừ AI", th: "ข้อสงวนสิทธิ์เกี่ยวกับ AI", pl: "Zastrzeżenie dot. AI" },
  "What AI-generated content is — and isn't": { en: "What AI-generated content is — and isn't", ar: "ما هو المحتوى المنشأ بالذكاء الاصطناعي وما ليس كذلك", "ar-eg": "إيه هو المحتوى اللي بيعمله الذكاء الاصطناعي.. وإيه اللي لأ", es: "Qué es (y qué no es) el contenido de IA", fr: "Qu'est-ce que le contenu généré par IA — et ce qu'il n'est pas", de: "Was KI-Inhalte sind - und was nicht", pt: "O que o conteúdo de IA é — e o que não é", it: "Cos'è il contenuto generato dall'IA — e cosa no", tr: "Yapay zeka içeriği nedir — ve ne değildir", ru: "Что такое контент от ИИ — а что нет", zh: "AI生成的内容是什么，不是什么", ja: "AI生成コンテンツとは何か、そうでないものは何か", ko: "AI 생성 콘텐츠란 무엇인가 — 그리고 무엇이 아닌가", hi: "AI-जनरेटेड कंटेंट क्या है — और क्या नहीं", id: "Apa itu konten buatan AI — dan apa yang bukan", nl: "Wat AI-content is — en wat niet", sv: "Vad AI-genererat innehåll är — och inte är", cs: "Co je obsah generovaný AI — a co není", ro: "Ce este (și ce nu este) conținutul generat de AI", el: "Τι είναι το περιεχόμενο AI — και τι δεν είναι", uk: "Що таке контент, створений ШІ — і чим він не є", he: "מהו תוכן שנוצר על ידי AI - ומה הוא לא", fa: "محتوای تولید شده توسط هوش مصنوعی چیست — و چه چیزی نیست", vi: "Nội dung do AI tạo ra là gì — và không là gì", th: "เนื้อหาที่สร้างโดย AI คืออะไร — และไม่ใช่คืออะไร", pl: "Czym jest (a czym nie jest) treść z AI" },
