  // ── Marketing — Security page ───────────────────────────────────────
  "Security &": { en: "Security &", ar: "الأمان و", "ar-eg": "الأمان و" },
  "Your data security is foundational to everything we build. Here's how we protect your creative work and personal information.": { en: "Your data security is foundational to everything we build. Here's how we protect your creative work and personal information.", ar: "أمان بياناتك أساس كل ما نبنيه. إليك كيف نحمي عملك الإبداعي ومعلوماتك الشخصية.", "ar-eg": "أمان بياناتك هو أساس كل حاجة بنبنيها. اتفرج إزاي بنحمي شغلك الإبداعي ومعلوماتك الشخصية." },
  "TLS 1.3 in transit and AES-256 at rest. API keys are hashed with bcrypt.": { en: "TLS 1.3 in transit and AES-256 at rest. API keys are hashed with bcrypt.", ar: "TLS 1.3 أثناء النقل وAES-256 عند التخزين. مفاتيح API مشفّرة بـ bcrypt.", "ar-eg": "TLS 1.3 أثناء النقل وAES-256 عند التخزين. مفاتيح API متشفّرة بـ bcrypt." },
  "SOC 2 cloud infra with automated backups, multi-region redundancy, 99.9% uptime SLA.": { en: "SOC 2 cloud infra with automated backups, multi-region redundancy, 99.9% uptime SLA.", ar: "بنية سحابية SOC 2 مع نسخ احتياطية آلية وتكرار متعدد المناطق وSLA بجاهزية 99.9٪.", "ar-eg": "بنية سحابية SOC 2 بنسخ احتياطية أوتوماتيك وتكرار متعدد المناطق وSLA بجاهزية 99.9٪." },
  "Authentication": { en: "Authentication", ar: "المصادقة", "ar-eg": "التوثيق" },
  "Industry-standard auth, optional 2FA, secure sessions, automatic expiration.": { en: "Industry-standard auth, optional 2FA, secure sessions, automatic expiration.", ar: "مصادقة بمعايير الصناعة، 2FA اختياري، جلسات آمنة، انتهاء صلاحية تلقائي.", "ar-eg": "مصادقة بمعايير الصناعة، 2FA اختياري، جلسات آمنة، انتهاء صلاحية أوتوماتيك." },
  "Access control": { en: "Access control", ar: "التحكم في الوصول", "ar-eg": "التحكم في الوصول" },
  "RBAC across systems. Least-privilege enforced. All access is logged.": { en: "RBAC across systems. Least-privilege enforced. All access is logged.", ar: "RBAC عبر الأنظمة، مبدأ الأقل امتيازًا مطبَّق، كل وصول مسجَّل.", "ar-eg": "RBAC عبر الأنظمة، مبدأ الأقل امتيازًا مطبق، كل وصول متسجل." },
  "GDPR and CCPA compliant. Regular privacy impact assessments and DPAs.": { en: "GDPR and CCPA compliant. Regular privacy impact assessments and DPAs.", ar: "متوافق مع GDPR وCCPA. تقييمات دورية لأثر الخصوصية واتفاقيات DPA.", "ar-eg": "متوافق مع GDPR وCCPA. تقييمات دورية لأثر الخصوصية واتفاقيات DPA." },
  "Incident response": { en: "Incident response", ar: "الاستجابة للحوادث", "ar-eg": "الاستجابة للحوادث" },
  "24/7 monitoring. Documented plan, <1 hour response, 72h GDPR notice.": { en: "24/7 monitoring. Documented plan, <1 hour response, 72h GDPR notice.", ar: "مراقبة 24/7. خطة موثّقة، استجابة أقل من ساعة، إشعار GDPR خلال 72 ساعة.", "ar-eg": "مراقبة 24/7. خطة موثّقة، رد في أقل من ساعة، إشعار GDPR خلال 72 ساعة." },
  "Data residency": { en: "Data residency", ar: "موقع البيانات", "ar-eg": "موقع البيانات" },
  "Export anytime. Full deletion upon account closure within 30 days.": { en: "Export anytime. Full deletion upon account closure within 30 days.", ar: "التصدير في أي وقت. حذف كامل عند إغلاق الحساب خلال 30 يومًا.", "ar-eg": "تقدر تصدّر أي وقت. حذف كامل بعد إغلاق الحساب خلال 30 يوم." },
